run("git", ["bundle", "verify", bundlePath], { capture: true });

const args = [
  "run",
  "--rm",
  "--platform",
  platform,
  "--cpus",
  cpus,
  "--memory",
  memory,
  ...(platform === "linux/amd64" ? ["--rosetta"] : []),
  "--mount",
  `type=bind,source=${bundleDirectory},target=/input,readonly`,
  "--mount",
  `type=volume,source=${storeVolume},target=/pnpm-store`,
  "--env",
