1	import assert from "node:assert/strict";
2	import { appendFileSync, readFileSync, writeFileSync } from "node:fs";
3	import { resolve } from "node:path";
4	import { readJson, root, run, suiteConfig } from "./lib.mjs";
5	import { readReleasePlan } from "./release-plan.mjs";
6	import { assertReleaseRecordCommit, parseReleaseRecord } from "./release-record.mjs";
7	import { bumpVersion } from "./version.mjs";
8	
9	const sourceSha = process.argv[2];
10	if (!sourceSha) throw new Error("usage: prepare.mjs <source-sha>");
11	assert.match(sourceSha, /^[0-9a-f]{40}$/, "release source must be a full commit SHA");
12	
13	const git = (args, options = {}) => run("git", args, { capture: true, ...options }).trim();
14	const writeJson = (path, value) => writeFileSync(path, `${JSON.stringify(value, null, 2)}\n`);
15	const config = suiteConfig();
16	const packageIds = config.packages.map(({ id }) => id);
17	const manifestPath = (entry) => `${entry.path}/package.json`;
18	const packageManifestPaths = Object.fromEntries(
19	  config.packages.map((entry) => [entry.id, manifestPath(entry)]),
20	);
21	const changedFilesAt = (commit) =>
22	  git(["diff-tree", "--no-commit-id", "--name-status", "-r", commit])
23	    .split(/\r?\n/)
24	    .filter(Boolean)
25	    .map((line) => {
26	      const [status, path] = line.split("\t");
27	      return { status, path };
28	    });
29	const manifestVersionsAt = (commit) =>
30	  Object.fromEntries(
31	    config.packages.map((entry) => [
32	      entry.id,
33	      JSON.parse(git(["show", `${commit}:${manifestPath(entry)}`])).version,
34	    ]),
35	  );
36	const releaseCommits = () => {
37	  const records = git(["log", "origin/main", "--format=%H%x1f%P%x1f%B%x1e"]);
38	  return records.split("\x1e").flatMap((raw) => {
39	    const [commit, rawParents = "", message = ""] = raw.trim().split("\x1f", 3);
40	    if (!commit) return [];
41	    const record = parseReleaseRecord(message);
42	    if (record === undefined) return [];
43	    assertReleaseRecordCommit({
44	      record,
45	      parents: rawParents.split(/\s+/).filter(Boolean),
46	      manifestVersions: manifestVersionsAt(commit),
47	      packageIds,
48	      packageManifestPaths,
49	      changedFiles: changedFilesAt(commit),
50	    });
51	    return [{ commit, record }];
52	  });
53	};
54	
55	git(["cat-file", "-e", `${sourceSha}^{commit}`]);
56	const releases = releaseCommits();
57	const matching = releases.filter(({ record }) => record.source === sourceSha);
58	if (matching.length > 1) throw new Error("one source commit has multiple release records");
59	const existing = matching[0];
60	if (existing) {
61	  git(["checkout", "--detach", existing.commit]);
62	} else {
63	  if (git(["rev-parse", "HEAD"]) !== sourceSha) {
64	    throw new Error("new release preparation must run from the source commit");
65	  }
66	  if (
67	    process.env.PI_SUITE_RELEASE_PREVIEW !== "1" &&
68	    git(["rev-parse", "origin/main"]) !== sourceSha
69	  ) {
70	    throw new Error(
71	      "release source is no longer origin/main; wait for each main release before pushing the next source",
72	    );
73	  }
74	}
75	
76	const pending = existing ? null : readReleasePlan();
77	if (!existing && releases[0]) {
78	  const expectedVersions = manifestVersionsAt(releases[0].commit);
79	  for (const entry of config.packages) {
80	    const currentVersion = readJson(manifestPath(entry)).version;
81	    if (currentVersion !== expectedVersions[entry.id]) {
82	      throw new Error(
83	        `${entry.id} version is CI-owned; expected ${expectedVersions[entry.id]}, received ${currentVersion}`,
84	      );
85	    }
86	  }
87	}
88	const selected = existing
89	  ? existing.record.packages.map((released) => {
90	      const entry = config.packages.find(({ id }) => id === released.id);
91	      assert.ok(entry, `existing release names unknown package ${released.id}`);
92	      return { ...entry, bump: released.bump, version: released.version };
93	    })
94	  : pending.packages.map((entry) => {
95	      const path = manifestPath(entry);
96	      const manifest = readJson(path);
97	      const version = bumpVersion(manifest.version, entry.bump);
98	      manifest.version = version;
99	      writeJson(resolve(root, path), manifest);
100	      return { ...entry, version };
101	    });
102	
